#!/usr/bin/env node
// ============================================================
// update_restaurants.cjs  —  run from project root:
//   node update_restaurants.cjs
// ============================================================
const fs = require("fs");
const path = require("path");

const RESTAURANTS_PATH = path.join(__dirname, "src/data/restaurants.js");
let src = fs.readFileSync(RESTAURANTS_PATH, "utf8");
const originalLen = src.length;
console.log(`📖 Read restaurants.js (${originalLen.toLocaleString()} bytes)`);

// ── 1. REMOVE 2 RESTAURANTS WITH NO PHOTOS ──────────────────
const REMOVE_NAMES = ["The Surf Club", "Pleasure Wine & Cocktail Bar"];
for (const name of REMOVE_NAMES) {
  const lines = src.split("\n");
  const before = lines.length;
  const filtered = lines.filter(l => !l.includes(`name:"${name}"`));
  if (filtered.length < before) {
    src = filtered.join("\n");
    console.log(`✅ Removed: "${name}"`);
  } else {
    console.warn(`⚠️  Not found: "${name}" — check exact name in restaurants.js`);
  }
}

// ── 2. ADD CITIES ────────────────────────────────────────────
const NEW_CITIES = ["Dallas","Dubai","Tokyo","Paris","San Diego","Barcelona","Copenhagen"];
for (const city of NEW_CITIES) {
  if (!src.includes(`"${city}"`)) {
    src = src.replace(/export const CITIES = \[/, `export const CITIES = [\n  "${city}",`);
    console.log(`✅ CITIES += ${city}`);
  }
}

// ── 3. ADD CITY_GROUPS ───────────────────────────────────────
const NEW_GROUPS = {
  "Dallas":"United States","Dubai":"International","Tokyo":"International",
  "Paris":"International","San Diego":"United States","Barcelona":"International",
  "Copenhagen":"International"
};
for (const [city, group] of Object.entries(NEW_GROUPS)) {
  if (!src.includes(`"${city}":`)) {
    src = src.replace(/(export const CITY_GROUPS = \{[\s\S]*?)(\n\};)/, `$1\n  "${city}": "${group}",$2`);
    console.log(`✅ CITY_GROUPS += ${city}`);
  }
}

// ── 4. ADD CITY_COORDS ───────────────────────────────────────
const NEW_COORDS = {
  "Dallas":     {lat:32.7767,lng:-96.7970},
  "Dubai":      {lat:25.2048,lng:55.2708},
  "Tokyo":      {lat:35.6762,lng:139.6503},
  "Paris":      {lat:48.8566,lng:2.3522},
  "San Diego":  {lat:32.7157,lng:-117.1611},
  "Barcelona":  {lat:41.3851,lng:2.1734},
  "Copenhagen": {lat:55.6761,lng:12.5683},
};
for (const [city, c] of Object.entries(NEW_COORDS)) {
  if (!src.includes(`"${city}": {`)) {
    src = src.replace(/(export const CITY_COORDS = \{[\s\S]*?)(\n\};)/, `$1\n  "${city}": { lat: ${c.lat}, lng: ${c.lng} },$2`);
    console.log(`✅ CITY_COORDS += ${city}`);
  }
}

